{
    Trie trie;
    trie.insert("apple");
    cout << boolalpha << trie.search("apple") << ", ";
    cout << trie.search("app") << ", ";
    cout << trie.startsWith("app") << ", ";
    trie.insert("app");
    cout << trie.search("app");

    return 0;
}

#include <iostream>
#include <vector>
#include <string>

using namespace std;

class WordDictionary {
public:
    vector<string> words;

    void addWord(string word)
    {
        words.push_back(word);
    }

    bool matches(const string &word, const string &candidate)
    {
        if (word.size() != candidate.size()) return false;
        for (int i = 0; i < (int)word.size(); i++)
            if (word[i] != '.' && word[i] != candidate[i]) return false;
        return true;
    }

    bool search(string word)
    {
        for (auto &w : words) if (matches(word, w)) return true;
        return false;
    }
};

int main()
{
    WordDictionary wd;
    wd.addWord("bad");
    wd.addWord("dad");
    wd.addWord("mad");

    cout << boolalpha << wd.search("pad") << ", ";
    cout << wd.search("bad") << ", ";
    cout << wd.search(".ad") << ", ";
    cout << wd.search("b..");

    return 0;
}

#include <iostream>
#include <string>
#include <unordered_map>

using namespace std;

struct TrieNode {
    unordered_map<char, TrieNode*> children;
    bool isEndOfWord = false;
};

class WordDictionary {
public:
    TrieNode* root;

    WordDictionary()
    {
        root = new TrieNode();
    }

    void addWord(string word)
    {
        TrieNode* node = root;
        for (char c : word)
        {
            if (node->children.find(c) == node->children.end())
                node->children[c] = new TrieNode();
            node = node->children[c];
        }
        node->isEndOfWord = true;
    }

    bool dfs(TrieNode* node, const string &word, int index)
    {
        if (node == nullptr) return false;
        if (index == (int)word.size()) return node->isEndOfWord;

        char c = word[index];
        if (c == '.')
        {
            for (auto &entry : node->children)
                if (dfs(entry.second, word, index + 1)) return true;
            return false;
        }
        else
        {
            if (node->children.find(c) == node->children.end()) return false;
            return dfs(node->children[c], word, index + 1);
        }
    }

    bool search(string word)
    {
        return dfs(root, word, 0);
    }
};

int main()
{
    WordDictionary wd;
    wd.addWord("bad");
    wd.addWord("dad");
    wd.addWord("mad");

    cout << boolalpha << wd.search("pad") << ", ";
    cout << wd.search("bad") << ", ";
    cout << wd.search(".ad") << ", ";
    cout << wd.search("b..");

    return 0;
}

